INSERT INTO specialties (code, name, description, additional_info, career_paths, subjects) VALUES ('GATE', 'Génie Aéronautique et Technologies de l''Espace', 'L’écosystème aéronautique marocain représente l’un des plus beaux cas de réussite industrielle dans un pays en développement avec un important besoin en ingénieurs diplômés. Ainsi le Maroc est devenu un important acteur dans ce secteur industriel. Avec la présence des leaders du secteur aéronautique sur son sol, tels que Bombardier, EADS, Boeing, Safran, Thales, le Maroc a fait du secteur aéronautique un des plus importants dans son Plan d’accélération industriel 2014-2020. Le métier d’ingénieur aéronautique fait appel à des qualifications issues de multiples disciplines : physique, matériaux, informatique, mécanique, hydraulique, pneumatique, électronique, armement…Il travaille donc en équipe multidisciplinaire et internationalisée( anglais requis). Notre filière de spécialisation met la théorie en pratique de façon équilibrée et mène à un diplôme d’ingénierie en techniques aéronautique et aérospatiale, en Techniques de maintenance d''aéronefs ou en Techniques d''avionique, en plus, la formation est dotée de reconnaissance des codes et des normes de l''aviation civile nationales, européennes et de l''UAE. Par ailleurs Notre diplôme offre la possibilité à ses étudiants de passer les examens PART-66 de l’Agence européenne de sécurité aérienne (EASA) afin d’obtenir une licence de maintenance d’aéronefs (LMA) européenne en collaboration avec le NOVAe Aerospace. Cette filière est bien appuyée par des professionnels du domaines aéronautiques et spatiales à l’échelle nationale (CE3M, GIMAS…) et aussi internationale (NOVAE ,HCT …). Et dans son opérationnalisation many intervenants du monde de l’industrie vont animer et assister les apprentissages aux futures ingénieurs.', '[{"year": "1ère Année", "semesters": [{"name": "Semestre 1", "modules": [{"name": "Structures des avions, Technologies des aéronefs", "type": "common"}, {"name": "Fonctions électroniques", "type": "common"}, {"name": "Mécanique des fluides appliquée", "type": "common"}, {"name": "Matériaux plastiques et composites", "type": "common"}, {"name": "Thermopropulsion", "type": "common"}, {"name": "Langues étrangères 1 (Anglais/Français)", "type": "common"}, {"name": "Algorithmique et Programmation en Python", "type": "common"}]}, {"name": "Semestre 2", "modules": [{"name": "Conception aéronautique et Design Industriel", "type": "common"}, {"name": "Systèmes embarqués 1", "type": "common"}, {"name": "Système d''information", "type": "common"}, {"name": "Programmation pour l''ingénieur", "type": "common"}, {"name": "Analyse numérique / Equations Différentielles", "type": "common"}, {"name": "Langues étrangères 2 (Anglais/Français)", "type": "common"}, {"name": "Culture and Art Skills", "type": "common"}]}]}, {"year": "2ème Année", "semesters": [{"name": "Semestre 3", "modules": [{"name": "Commande des systèmes électriques des aéronefs", "type": "common"}, {"name": "Systèmes embarqués II", "type": "common"}, {"name": "Technologie des hélices", "type": "common"}, {"name": "Mécanique du vol et aérodynamique appliquée", "type": "common"}, {"name": "Technologies propulseurs et Moteurs à piston", "type": "common"}, {"name": "Langues étrangères 3 (Anglais/Français)", "type": "common"}, {"name": "Intelligence Artificielle et ses Applications", "type": "common"}]}, {"name": "Semestre 4", "modules": [{"name": "Hydraulique, Pneumatique / Météorologie aéronautique", "type": "common"}, {"name": "Calcul des structures en aéronautique", "type": "common"}, {"name": "CFAO et Machines Outils à commande", "type": "common"}, {"name": "Lean six sigma et Manufacturing", "type": "common"}, {"name": "Recherche opérationnelle, Optimisation et Modélisation", "type": "common"}, {"name": "Langues étrangères 4 (Anglais/Français)", "type": "common"}, {"name": "Management de projet et Entrepre- nariat", "type": "common"}]}]}, {"year": "3ème Année", "semesters": [{"name": "Semestre 5", "modules": [{"name": "Management Organisationnel et Management de Projets Complexes", "type": "common"}, {"name": "Smart manufacturing : Industrie 4.0", "type": "common"}, {"name": "Logistique Industrielle", "type": "common"}, {"name": "Aircraft Maintenance Practices", "type": "common"}, {"name": "Qualité, Sécurité et Environnement et réglementation aéronautique", "type": "common"}, {"name": "Langues étrangères 5 (Anglais/Français)", "type": "common"}, {"name": "Employment Skills", "type": "common"}]}, {"name": "Semestre 6", "modules": [{"name": "Projet de fin d''étude (PFE)", "type": "common"}]}]}]', 'ingénieur aéronautique, ingénieur interface client aéronautique, ingénieur études aéronautiques, consultant aerospace, ingénieur systèmes aéronautiques, ingénieur logiciel embarqué aéronautique, ingénieur assistance technique.', 'Aéronautique, Technologies spatiales, maintenance aéronautique, manufacturing aéronautique, smart-manufacturing.');
INSERT INTO specialties (code, name, description, additional_info, career_paths, subjects) VALUES ('GIIA', 'Génie Informatique et Intelligence Artificielle', '<strong>Option 1 : GÉNIE INFORMATIQUE</strong><br>L’option Ingénierie Informatique et Décisionnelle de l’ENSA-Safi répond à une demande nationale et régionale croissante des ingénieurs en développement informatique et l’informatique décisionnelle dans les différents secteurs industriels et de services, notre filière souhaite ainsi doter le tissu économique national et régional de cadre opérationnel dans les métiers de l’informatique, en développement, réseaux, base de données et sécurité informatique et en informatique décisionnelle. Ces vastes domaines, toujours en constante évolution, constitue l’objectif d’un ensemble d’enseignements techniques et scientifiques, d’autres modules complémentaires (sciences humaines, managements...), visent à permettre à d’autre demandes et besoins croissants où le profil d’ingénieur s’impose, de par ses connaissances, ses aptitudes, sa rigueur. Il s’agit de secteurs d’activités liés au tertiaire avancé, qu’il soit public ou privé et où les technologies de l’information constituent un outil incontournable dont on ne pourrait plusse passer. Elles sont dispensées durant les quatre derniers semestres. S’y ajoutent, des matières et des cours spécifiques permettant de caractériser la formation 8 / 303 propre à la filière informatique et réseaux et ses orientations. Elles font l’objet d’un enseignement durant les trois derniers semestres.<br><br><strong>Option 2 : INGÉNIERIE DES DONNÉES ET INTELLIGENCE ARTIFICIELLE</strong><br>"L''objectif principal de l’option IDIA est de former des ingénieurs, de haut niveau scientifique équilibré entre la théorie et la pratique, capables de récupérer, stocker, organiser et traiter de grandes masses d’informations, afin de faciliter leur compréhension et permettre aux dirigeants d''adopter les bonnes stratégies. Les lauréats de la filière IDIA sont par conséquent des acteur-clés pour la gestion de grandes sociétés. Techniquement parlant, la filière IDIA répond à une forte demande du marché du travail pour des compétences en technologies Big data, Datamining, intelligence artificielle et internet des objets. Elle constitue également une contribution à la concrétisation de la vision du Maroc à explorer les techniques de l’intelligence artificielle, afin de développer efficacement différents domaines socio-économiques."', '[{"year": "1ère Année", "semesters": [{"name": "Semestre 1", "modules": [{"name": "Ingénierie Financière", "type": "common"}, {"name": "Mathématiques pour l''Ingénieur", "type": "common"}, {"name": "Python pour la Data Science et le Machine Learning", "type": "common"}, {"name": "Systèmes d''Information", "type": "common"}, {"name": "Modélisation Stochastique", "type": "common"}, {"name": "Systèmes de Gestion de Contenu", "type": "common"}, {"name": "LC 1", "type": "common"}]}, {"name": "Semestre 2", "modules": [{"name": "Transition Écologique et Dynamiques Culturelles", "type": "common"}, {"name": "Techniques d''Optimisation Avancées", "type": "common"}, {"name": "Systèmes d''Exploitation et Environnements de Développement", "type": "common"}, {"name": "Modélisation UML", "type": "common"}, {"name": "Architecture des Systèmes", "type": "common"}, {"name": "Machine Learning", "type": "common"}, {"name": "LC 2", "type": "common"}]}]}, {"year": "2ème Année", "semesters": [{"name": "Semestre 3", "modules": [{"name": "Développement Backend en JS", "type": "gi"}, {"name": "Marketing et Développement Durable", "type": "common"}, {"name": "Bases de Données Avancées", "type": "common"}, {"name": "Méthodes Heuristiques et Méta-Heuristiques", "type": "gidia"}, {"name": "Projets Tutorés", "type": "common"}, {"name": "Analyse des Données", "type": "gidia"}, {"name": "Programmation Java Avancée", "type": "gi"}, {"name": "Développement Web Dynamique", "type": "gi"}, {"name": "LC 3", "type": "common"}]}, {"name": "Semestre 4", "modules": [{"name": "Gouvernance des Systèmes d''Information", "type": "gi"}, {"name": "Génie Logiciel", "type": "gi"}, {"name": "Systèmes Intelligents Flous", "type": "gidia"}, {"name": "Traitement d''Image / Vision Artificielle", "type": "common"}, {"name": "Internet des Objets", "type": "common"}, {"name": "Cloud Computing et Virtualisation", "type": "common"}, {"name": "Introduction à la Sécurité des Réseaux et Systèmes", "type": "common"}, {"name": "Management de Projet et Entrepreneuriat", "type": "common"}, {"name": "LC 4", "type": "common"}]}]}, {"year": "3ème Année", "semesters": [{"name": "Semestre 5", "modules": [{"name": "Architectures Réparties JEE", "type": "gi"}, {"name": "Ingénierie des Données Massives et Big Data", "type": "gidia"}, {"name": "Anglais", "type": "common"}, {"name": "Traitement Automatique du Langage Naturel", "type": "gidia"}, {"name": "Théorie des Jeux et Systèmes Multi-Agents", "type": "gidia"}, {"name": "Web Sémantique et Développement Mobile", "type": "common"}]}, {"name": "Semestre 6", "modules": [{"name": "Intégration et Solutions Métiers", "type": "common"}, {"name": "E-Management et Innovation / Innovation et Entrepreneuriat", "type": "common"}, {"name": "Sécurité des Systèmes d''Information et Technologie Blockchain", "type": "common"}, {"name": "Factory Management / Usine de Développement Logiciel", "type": "gi"}, {"name": "Projet de Fin d''Études", "type": "common"}]}]}]', 'Ingénieur Data Scientist, Ingénieur IA, Développeur Full-Stack, Architecte Logiciel, Consultant IT, Ingénieur Cloud, Ingénieur Cybersécurité, Chef de Projet Digital.', 'Informatique, Intelligence Artificielle, Machine Learning, Développement Logiciel, Big Data, Cloud Computing, Systèmes d''Information.');
INSERT INTO specialties (code, name, description, additional_info, career_paths, subjects) VALUES ('GINDUS', 'Génie Industriel', 'L''objectif de cette formation est de doter les ingénieurs en génie industriel des compétences nécessaires en management industriel. Le métier de l''ingénieur en génie industriel repose sur l''amélioration continue et l''optimisation des performances des entreprises dans divers domaines (technique, financier, organisationnel, humain). La formation répond à cette polyvalence en proposant, durant les trois premiers semestres, des enseignements techniques et scientifiques (électronique, informatique, mécanique, ... etc), suivis de formations managériales et spécifiques (production, maintenance, qualité, logistique, lean manufacturing,...etc) dans les deux derniers semestres. L''enjeu est de fournir aux futurs ingénieurs les outils et méthodes pour concevoir des systèmes et gérer efficacement les aspects économiques, financiers, humains et matériels des entreprises.', '[{"year": "1ère Année", "semesters": [{"name": "Semestre 1", "modules": [{"name": "Conception des systèmes mécaniques", "type": "common"}, {"name": "Systèmes de mesure et conception expérimentale", "type": "common"}, {"name": "Thermodynamique appliquée et phénomènes de transfert", "type": "common"}, {"name": "Calcul des structures", "type": "common"}, {"name": "Sciences des matériaux", "type": "common"}, {"name": "Langues étrangères", "type": "common"}, {"name": "Excel avancé", "type": "common"}]}, {"name": "Semestre 2", "modules": [{"name": "Machines électriques et électronique de puissance", "type": "common"}, {"name": "Procédés de fabrication mécanique", "type": "common"}, {"name": "Conception de circuits électroniques", "type": "common"}, {"name": "Automatique linéaire", "type": "common"}, {"name": "Recherche opérationnelle pour le génie industriel", "type": "common"}, {"name": "Compétences artistiques et culturelles", "type": "common"}, {"name": "Langues étrangères (anglais /français)", "type": "common"}]}]}, {"year": "2ème Année", "semesters": [{"name": "Semestre 3", "modules": [{"name": "Production et stockage de l''énergie", "type": "common"}, {"name": "Management de projet et de l''innovation", "type": "common"}, {"name": "Statistique décisionnelle", "type": "common"}, {"name": "Efficacité énergétique en milieu industriel", "type": "common"}, {"name": "Maintenance des systèmes industriels", "type": "common"}, {"name": "Intelligence artificielle et ses applications", "type": "common"}, {"name": "Langues étrangères", "type": "common"}]}, {"name": "Semestre 4", "modules": [{"name": "Electricité industrielle et automatisme", "type": "common"}, {"name": "Entreprenariat et gestion des entreprises", "type": "common"}, {"name": "Management de production", "type": "common"}, {"name": "Langues étrangères", "type": "common"}, {"name": "Mini projet", "type": "common"}, {"name": "Management de projet et entrepreneuriat", "type": "common"}, {"name": "Management qualité", "type": "common"}]}]}, {"year": "3ème Année", "semesters": [{"name": "Semestre 5", "modules": [{"name": "Industrie 4.0", "type": "common"}, {"name": "Lean manufacturing et amélioration des processus", "type": "common"}, {"name": "Logistique et suply chain Management", "type": "common"}, {"name": "Langues étrangères", "type": "common"}, {"name": "Employment skills", "type": "common"}, {"name": "Ergonomie et HSE (Hygiène, Sécurité, Environnement)", "type": "common"}, {"name": "Supervision des systèmes industriels", "type": "common"}]}, {"name": "Semestre 6", "modules": [{"name": "Projet de fin d''étude (PFE)", "type": "common"}]}]}]', 'Production industrielle, maintenance industrielle, management de projet, qualité industrielle, sécurité et environnement (QSE), logistique et supply chain, organisation et optimisation des processus, gestion des opérations, amélioration continue et lean management, conseil et ingénierie industrielle.', 'Génie Industriel, Management Industriel, Amélioration Continue, Lean Manufacturing, Logistique, Supply Chain, Maintenance, Qualité HSE, Production, Optimisation des performances, Ingénierie des systèmes, ERP, Gestion de projet.');
INSERT INTO specialties (code, name, description, additional_info, career_paths, subjects) VALUES ('GMSI', 'Génie Mécatronique et systèmes intelligents', 'La filière "Mécatronique et Systèmes Intelligents" combine la mécanique, l''électronique, l''informatique et l''automatique pour concevoir des systèmes intégrés et intelligents. Elle forme des ingénieurs capables de développer des robots, des machines autonomes, et des dispositifs embarqués. Les étudiants apprennent à maîtriser la modélisation, la programmation, et l''optimisation des systèmes complexes. Cette formation prépare à des carrières dans l''automobile, l''aéronautique, la robotique et les technologies de pointe.', '[{"year": "1ère Année", "semesters": [{"name": "Semestre 1", "modules": [{"name": "Electronique Numérique", "type": "common"}, {"name": "Conception des Systèmes Mécaniques", "type": "common"}, {"name": "Systèmes Analogiques Avancés", "type": "common"}, {"name": "Programmation Orientée Objet en C++", "type": "common"}, {"name": "Systèmes de Mesure et Conception Expérimentale", "type": "common"}, {"name": "Algorithmique et Programmation en Python", "type": "common"}, {"name": "Langues Étrangères (Anglais/Français)", "type": "common"}]}, {"name": "Semestre 2", "modules": [{"name": "Programmation des microcontrôleurs CORTEX M4", "type": "common"}, {"name": "Mécanique des Milieux Continues et Mécanique des Fluides", "type": "common"}, {"name": "Électronique de Puissance", "type": "common"}, {"name": "Électrotechnique", "type": "common"}, {"name": "Propriétés Mécaniques et Thermiques des Matériaux", "type": "common"}, {"name": "Créativité visuelle et innovation numérique", "type": "common"}, {"name": "Traitement du signal et simulation de circuits électroniques", "type": "common"}, {"name": "Langues Etrangères (Anglais /Français)", "type": "common"}]}]}, {"year": "2ème Année", "semesters": [{"name": "Semestre 3", "modules": [{"name": "Base de Données et Réseaux Informatiques", "type": "common"}, {"name": "Systèmes Hydrauliques et Pneumatiques", "type": "common"}, {"name": "Calcul des Structures et RDM", "type": "common"}, {"name": "Systèmes Embarqués pour l''Automobile et Automate Programmable", "type": "common"}, {"name": "Systèmes Asservis", "type": "common"}, {"name": "Intelligence Artificielle et ses Applications", "type": "common"}, {"name": "Langues Étrangères (Anglais/Français)", "type": "common"}]}, {"name": "Semestre 4", "modules": [{"name": "Informatique Embarquée", "type": "common"}, {"name": "Circuits programmables", "type": "common"}, {"name": "Capteurs intelligents industriels et chaine d''acquisition", "type": "common"}, {"name": "Maintenance 4.0", "type": "common"}, {"name": "Management de projet et entrepreneuriat", "type": "common"}, {"name": "Management intégré qualité, sécurité et environnement", "type": "common"}, {"name": "Mini projets", "type": "common"}, {"name": "Langues étrangères (français /anglais)", "type": "common"}]}]}, {"year": "3ème Année", "semesters": [{"name": "Semestre 5", "modules": [{"name": "Pilotage des performances et excellence opérationnelle", "type": "common"}, {"name": "Systèmes mécatroniques de l''automobile", "type": "common"}, {"name": "Robotique et systèmes intelligents", "type": "common"}, {"name": "Employment skills", "type": "common"}, {"name": "Outils de modélisation et simulation automobile", "type": "common"}, {"name": "Internet des objets", "type": "common"}, {"name": "Commande intelligente", "type": "common"}, {"name": "Langues étrangères (français /anglais)", "type": "common"}]}, {"name": "Semestre 6", "modules": [{"name": "Projet de fin d''étude (PFE)", "type": "common"}]}]}]', 'Chef de projet en systèmes mécatroniques, gestion de maintenance et sûreté de fonctionnement, ingénieur en conception et développement mécatronique, bureaux d’études, industrie automobile, industrie aéronautique, énergies renouvelables, robotique industrielle, ingénieur-conseil.', 'Mécatronique, Systèmes Intelligents, Robotique, Automatique, Systèmes Embarqués, Mécanique, Electronique, Informatique, Automobile, Aéronautique, Energies Renouvelables, Maintenance, IA. ');
INSERT INTO specialties (code, name, description, additional_info, career_paths, subjects) VALUES ('GPMA', 'Génie des Procédés & Matériaux Avancés', 'La filière génie des procédés et matériaux avancés a pour objectifs de répondre au marché de l''emploi with plus d''ouverture vers la culture projet et le monde industriel. L''ingénieur on Génie des Procédés & Matériaux Avancés est fondamentalement un manager de la production, ouvert on l''international. Il est capable de concevoir, d''implanter et de piloter un système de production en tenant compte des caractéristiques scientifiques, technologiques, économiques et humaines.', '[{"year": "1ère Année", "semesters": [{"name": "Semestre 1", "modules": [{"name": "Opérations unitaires", "type": "common"}, {"name": "Physico-chimie des matériaux solides", "type": "common"}, {"name": "Instrumentation, mesures et plan d''expérience", "type": "common"}, {"name": "Résistance des matériaux et simulation numérique par éléments finis", "type": "common"}, {"name": "Systèmes thermiques et énergétiques", "type": "common"}, {"name": "Algorithmique et programmation en Python", "type": "common"}, {"name": "Langues étrangères", "type": "common"}]}, {"name": "Semestre 2", "modules": [{"name": "Echangeurs de chaleur industriels et machines hydrauliques", "type": "common"}, {"name": "Energies renouvelables", "type": "common"}, {"name": "Techniques de caractérisation des matériaux", "type": "common"}, {"name": "Recherche opérationnelle pour le génie industriel", "type": "common"}, {"name": "Automatique linéaire", "type": "common"}, {"name": "Algorithmique et programmation en Python", "type": "common"}, {"name": "Langues étrangères", "type": "common"}]}]}, {"year": "2ème Année", "semesters": [{"name": "Semestre 3", "modules": [{"name": "Cristallisation industrielle et filtration", "type": "common"}, {"name": "Pilotage des performances et excellence opérationnelle", "type": "common"}, {"name": "Procédés de l''environnement et dessalement de l''eau de mer", "type": "common"}, {"name": "Statistique décisionnelle", "type": "common"}, {"name": "Métallurgie et traitement de surface", "type": "common"}, {"name": "Intelligence artificielle et ses applications", "type": "common"}, {"name": "Langues étrangères", "type": "common"}]}, {"name": "Semestre 4", "modules": [{"name": "Technologie des matériaux céramiques", "type": "gi"}, {"name": "Propriétés mécaniques et thermiques des matériaux", "type": "gi"}, {"name": "Commande des procédés industriels", "type": "gidia"}, {"name": "Génie réacteurs chimiques / Milieux poreux et dispersés", "type": "gidia"}, {"name": "Théories et pratiques des fours et des sécheurs industriels", "type": "gidia"}, {"name": "Management des entreprises et de projets", "type": "common"}, {"name": "Management de production", "type": "common"}, {"name": "Management intégré qualité, sécurité et environnement", "type": "common"}, {"name": "Mini projet", "type": "common"}, {"name": "Langues étrangères", "type": "common"}]}]}, {"year": "3ème Année", "semesters": [{"name": "Semestre 5", "modules": [{"name": "Protection anticorrosion par revêtements", "type": "gi"}, {"name": "Matériaux durables et procédés de fabrication additive", "type": "gi"}, {"name": "Matériaux innovants, intelligents et nouvelles technologies", "type": "gi"}, {"name": "Matériaux composites et polymères", "type": "gi"}, {"name": "Stockage d''énergie et audit énergétique des procédés industriels", "type": "gidia"}, {"name": "Simulation des procédés industriels", "type": "gidia"}, {"name": "Cycle de vie, impact environnemental et sécurité des procédés", "type": "gidia"}, {"name": "Réalité virtuelle et réalité augmentée", "type": "gidia"}, {"name": "Technologies hydrogène et matériaux énergétiques", "type": "gidia"}, {"name": "Industrie 4.0", "type": "common"}, {"name": "Employment skills", "type": "common"}, {"name": "Langues étrangères", "type": "common"}]}, {"name": "Semestre 6", "modules": [{"name": "Projet de Fin d''Etudes (PFE)", "type": "common"}]}]}]', 'Conduite des procédés industriels, qualité industrielle, gestion énergétique et environnementale, sécurité industrielle, production, recherche et développement (R&D), services technico-commerciaux, après-vente, vente industrielle, achats techniques.', 'Génie des Procédés, Matériaux Avancés, Management de Production, Durabilité, R&D, Qualité HSE, Procédés Industriels, Matériaux Innovants, Digitalisation, Industrie 4.0, Simulation, Corrosion, Composites.');
INSERT INTO specialties (code, name, description, additional_info, career_paths, subjects) VALUES ('GTR', 'Génie des Télécommunications et Réseaux', 'Les diplômés de la filière GTR de l’ENSA-Safi accèdent à divers métiers dans les secteurs des télécommunications, des réseaux et de la cybersécurité. Ils peuvent travailler comme ingénieurs en réseaux, en télécoms, en administration et en sécurité des systèmes, ou encore en développement et intégration de solutions. Avec la montée des cybermenaces, les spécialistes en sécurité des réseaux et de l’IoT sont particulièrement recherchés. Ils peuvent évoluer dans des entreprises de télécommunications, des sociétés de services numériques, des startups ou encore en tant que consultants indépendants. L''entrepreneuriat et la recherche en nouvelles technologies offrent également des opportunités prometteuses.', '[{"year": "1ère Année", "semesters": [{"name": "Semestre 1", "modules": [{"name": "Théorie de l''information et codage", "type": "common"}, {"name": "Signaux et systèmes", "type": "common"}, {"name": "Electronique analogique", "type": "common"}, {"name": "Mathématiques Appliquées pour l''ingénieur", "type": "common"}, {"name": "Système d''information", "type": "common"}, {"name": "Langues Etrangères (Anglais /Français)", "type": "common"}, {"name": "Systèmes de Gestion de Contenu (CMS)", "type": "common"}]}, {"name": "Semestre 2", "modules": [{"name": "Architecture des Systèmes", "type": "common"}, {"name": "Systèmes de Communications Analogiques", "type": "common"}, {"name": "Propagation et Antennes", "type": "common"}, {"name": "Probabilités et Processus stochastiques", "type": "common"}, {"name": "Introduction aux réseaux informatiques", "type": "common"}, {"name": "Culture and Art skills", "type": "common"}, {"name": "Langues Etrangères (Anglais /Français)", "type": "common"}]}]}, {"year": "2ème Année", "semesters": [{"name": "Semestre 3", "modules": [{"name": "Electronique numérique", "type": "common"}, {"name": "Réseaux optiques et sécurité des données", "type": "common"}, {"name": "Ingénierie de la Décision et Optimisation par la Recherche Opérationnelle (IDORO)", "type": "common"}, {"name": "Transmission Numérique en Bande de Base", "type": "common"}, {"name": "Techniques de Modulations Numériques", "type": "common"}, {"name": "Langues Etrangères (Français /Anglais)", "type": "common"}, {"name": "Intelligence artificielle et ses applications", "type": "common"}]}, {"name": "Semestre 4", "modules": [{"name": "Administration Avancée des Systèmes et Réseaux sous GNU/Linux", "type": "common"}, {"name": "Réseaux cellulaires et planification mobile", "type": "common"}, {"name": "Systèmes de communication radio", "type": "common"}, {"name": "Traitement d''images (TI)", "type": "common"}, {"name": "Génie logiciel et systèmes intelligents", "type": "common"}, {"name": "Langues Etrangères (Français /Anglais)", "type": "common"}, {"name": "Management de Projet et entrepreneuriat", "type": "common"}]}]}, {"year": "3ème Année", "semesters": [{"name": "Semestre 5", "modules": [{"name": "Cryptographie et sécurité des systèmes d''information et réseaux (CSSIR)", "type": "common"}, {"name": "Automatisation robotisée des processus (RPA)", "type": "common"}, {"name": "Sécurité des objets connectés (IOT)", "type": "common"}, {"name": "Cloud Computing", "type": "common"}, {"name": "technologie de réseau étendu", "type": "common"}, {"name": "Langues Etrangères (Anglais /Français)", "type": "common"}, {"name": "Employment Skills", "type": "common"}]}, {"name": "Semestre 6", "modules": [{"name": "Projet de fin d''étude (PFE)", "type": "common"}]}]}]', 'Ingénieur réseaux, ingénieur télécommunications, administrateur systèmes et réseaux, ingénieur cybersécurité, spécialiste en sécurité des réseaux, ingénieur IoT, développeur et intégrateur de solutions, consultant en réseaux et télécoms, entrepreneur technologique, chercheur en nouvelles technologies.', 'Télécommunications, Réseaux, Cybersécurité, Internet des Objets (IoT), Ingénieur télécoms, Administration des réseaux, Sécurité des systèmes, Cloud Computing, Infrastructure réseau, Optimisation des réseaux mobiles, Consultant en cybersécurité, Développement et intégration, Virtualisation, Entrepreneuriat, Intelligence artificielle appliquée aux réseaux, Startups technologiques, Sociétés de services numériques (ESN), Innovation technologique, Infrastructure critique, Recherche et développement (R&D).');
INSERT INTO questions (texte, texte_en, texte_ar, dimensions) VALUES
 ('J’aime organiser et améliorer le fonctionnement d’une entreprise.', 'I like organizing and improving the operations of a company.', 'أحب تنظيم وتحسين سير عمل الشركة.', 'D5,D6'),
 ('J’aime résoudre des problèmes mathématiques.', 'I love solving mathematical problems.', 'أحب حل المشكلات الرياضية.', 'D1'),
 ('Je m’intéresse à la façon dont l’information est transmise entre des appareils.', 'I am interested in how information is transmitted between devices.', 'أهتم بكيفية انتقال المعلومات بين الأجهزة.', 'D3'),
 ('J’aime programmer et développer des applications numériques.', 'I love programming and developing digital applications.', 'أحب البرمجة وتطوير التطبيقات الرقمية.', 'D2'),
 ('Je m’intéresse à la manière dont les matériaux sont créés et améliorés.', 'I am interested in how materials are created and improved.', 'أهتم بكيفية إنشاء المواد وتحسينها.', 'D5'),
 ('J’aime travailler en équipe sur des projets complexes.', 'I like working in a team on complex projects.', 'أحب العمل ضمن فريق في مشاريع معقدة.', 'D6'),
 ('J’aime comprendre comment les systèmes de communication relient les personnes et les appareils.', 'I like understanding how communication systems connect people and devices.', 'أحب فهم كيف تربط أنظمة الاتصال الأشخاص والأجهزة.', 'D3'),
 ('Je préfère les projets pratiques où je construis et teste des systèmes.', 'I prefer hands-on projects where I build and test systems.', 'أفضل المشاريع العملية حيث أقوم ببناء واختبار الأنظمة.', 'D4'),
 ('Je suis curieux(se) de comprendre comment de grandes quantités de données aident à prendre des décisions.', 'I am curious to understand how large amounts of data help in decision-making.', 'أنا فضولي لفهم كيف تساعد كميات كبيرة من البيانات في اتخاذ القرارات.', 'D2,D6'),
 ('Je suis attiré(e) par les secteurs liés aux transports avancés ou à l’aéronautique.', 'I am attracted to sectors related to advanced transport or aeronautics.', 'أنجذب إلى القطاعات المتعلقة بالنقل المتقدم أو الطيران والفضاء.', 'D4'),
 ('J’aime analyser les coûts, l’efficacité et la performance d’une organisation.', 'I like analyzing the costs, efficiency, and performance of an organization.', 'أحب تحليل التكاليف والكفاءة وأداء المؤسسة.', 'D5,D6'),
 ('J’aime analyser et améliorer les processus de production industrielle.', 'I like analyzing and improving industrial production processes.', 'أحب تحليل وتحسين عمليات الإنتاج الصناعي.', 'D5'),
 ('J’aime concevoir des systèmes numériques ou des solutions web.', 'I love designing digital systems or web solutions.', 'أحب تصميم الأنظمة الرقمية أو حلول الويب.', 'D2'),
 ('Je m’intéresse aux robots ou aux machines intelligentes.', 'I am interested in robots or intelligent machines.', 'أهتم بالروبوتات أو الآلات الذكية.', 'D4'),
 ('Je suis sensible à la protection des systèmes numériques et des informations.', 'I am concerned about protecting digital systems and information.', 'أهتم بحماية الأنظمة الرقمية والمعلومات.', 'D2,D8'),
 ('Je me sens à l’aise pour appliquer les mathématiques et la physique à des problèmes concrets.', 'I feel comfortable applying mathematics and physics to concrete problems.', 'أشعر بالارتياح عند تطبيق الرياضيات والفيزياء على مشكلات ملموسة.', 'D1'),
 ('J’intéresse à la gestion de projets et à la coordination d’équipes.', 'I am interested in project management and team coordination.', 'أهتم بإدارة المشاريع وتنسيق الفرق.', 'D6'),
 ('J’aime comprendre comment fonctionnent les avions ou les véhicules complexes.', 'I like understanding how planes or complex vehicles work.', 'أحب فهم كيفية عمل الطائرات أو المركبات المعقدة.', 'D4'),
 ('J’aime résoudre des problèmes logiques à l’aide d’algorithmes.', 'I like solving logical problems using algorithms.', 'أحب حل المشكلات المنطقية باستخدام الخوارزميات.', 'D1,D2'),
 ('Je m’intéresse aux technologies modernes de communication et aux objets connectés.', 'I am interested in modern communication technologies and connected objects.', 'أهتم بتقنيات الاتصال الحديثة والأشياء المتصلة.', 'D3'),
 ('Je suis sensible aux questions d’énergie et d’impact environnemental dans l’industrie.', 'I am concerned about energy issues and environmental impact in industry.', 'أهتم بقضايا الطاقة والتأثير البيئي في الصناعة.', 'D5,D8'),
 ('J’aime concevoir des systèmes utilisant des capteurs ou des dispositifs automatisés.', 'I like designing systems using sensors or automated devices.', 'أحب تصميم أنظمة تستخدم أجهزة استشعار أو أجهزة آلية.', 'D4'),
 ('Je me sens à l’aise pour prendre des décisions qui tiennent compte des aspects techniques et économiques.', 'I feel comfortable making decisions that consider both technical and economic aspects.', 'أشعر بالارتياح لاتخاذ قرارات تأخذ في الاعتبار الجوانب التقنية والاقتصادية.', 'D6'),
 ('J’aime analyser des signaux ou des informations numériques.', 'I like analyzing digital signals or information.', 'أحب تحليل الإشارات الرقمية أو المعلومات.', 'D2,D3'),
 ('Je m’intéresse à l’intelligence artificielle et à l’analyse des données.', 'I am interested in artificial intelligence and data analysis.', 'أهتم بالذكاء الاصطناعي وتحليل البيانات.', 'D2'),
 ('J’aime résoudre des problèmes techniques à l’aide de modèles ou de simulations.', 'I like solving technical problems using models or simulations.', 'أحب حل المشكلات التقنية باستخدام النماذج أو المحاكاة.', 'D1,D7'),
 ('Je m’intéresse à la logistique, à la planification de production ou à la gestion des flux.', 'I am interested in logistics, production planning, or flow management.', 'أهتم باللوجستيات أو تخطيط الإنتاج أو إدارة التدفقات.', 'D5'),
 ('Je me sens à l’aise pour utiliser des données afin d’améliorer les performances d’un système de production.', 'I feel comfortable using data to improve the performance of a production system.', 'أشعر بالارتياح لاستخدام البيانات لتحسين أداء نظام الإنتاج.', 'D2,D5'),
 ('Je m’intéresse à l’amélioration de la performance et de la fiabilité des systèmes techniques.', 'I am interested in improving the performance and reliability of technical systems.', 'أهتم بتحسين أداء وموثوقية الأنظمة التقنية.', 'D8'),
 ('Je suis attiré(e) par les technologies innovantes en informatique.', 'I am attracted to innovative technologies in computer science.', 'أنجذب إلى التقنيات المبتكرة في علوم الكمبيوتر.', 'D2'),
 ('J’aime comprendre comment les matières premières sont transformées en produits finis.', 'I like understanding how raw materials are transformed into finished products.', 'أحب فهم كيفية تحويل المواد الخام إلى منتجات نهائية.', 'D5'),
 ('J’aime travailler with des systèmes qui gèrent de grandes quantités d’informations.', 'I like working with systems that manage large amounts of information.', 'أحب العمل avec الأنظمة التي تدير كميات كبيرة من المعلومات.', 'D2'),
 ('Je m’intéresse aux technologies intelligentes et automatisées.', 'I am interested in smart and automated technologies.', 'أهتم بالتقنيات الذكية والآلية.', 'D4'),
 ('Je préfère améliorer un système existant plutôt que d’en inventer un totalement nouveau.', 'I prefer improving an existing system rather than inventing a completely new one.', 'أفضل تحسين نظام موجود بدلاً من اختراع نظام جديد تمامًا.', 'D5,D8'),
 ('Je m’intéresse aux systèmes techniques complexes qui exigent un haut niveau de sécurité.', 'I am interested in complex technical systems that require a high level of security.', 'أهتم بالأنظمة التقنية المعقدة التي تتطلب مستوى عالٍ من الأمان.', 'D8'),
 ('J’aime comprendre comment sont organisés les systèmes de production industrielle.', 'I like understanding how industrial production systems are organized.', 'أحب فهم كيفية تنظيم أنظمة الإنتاج الصناعي.', 'D5'),
 ('J’aime travailler with des machines et des équipements techniques.', 'I like working with machines and technical equipment.', 'أحب العمل avec الآلات والمعدات التقنية.', 'D4'),
 ('J’aime lire des articles scientifiques ou techniques.', 'I like reading scientific or technical articles.', 'أحب قراءة المقالات العلمية أو التقنية.', 'D7'),
 ('Je suis intéressé(e) par la recherche pour mieux comprendre le fonctionnement des choses.', 'I am interested in research to better understand how things work.', 'أهتم بالبحث لفهم كيفية عمل الأشياء بشكل أفضل.', 'D7'),
 ('J’aime rédiger des rapports ou des comptes rendus structurés.', 'I like writing structured reports or accounts.', 'أحب كتابة التقارير أو المحاضر المنظمة.', 'D6,D7'),
 ('Je préfère les tâches clairement définies et bien organisées.', 'I prefer clearly defined and well-organized tasks.', 'أفضل المهام المحددة بوضوح والمنظمة جيدًا.', 'D5,D6'),
 ('J’aime diriger ou coordonner un groupe pour réaliser un projet.', 'I like leading or coordinating a group to carry out a project.', 'أحب قيادة أو تنسيق مجموعة لإنجاز مشروع.', 'D6');
